package com.infy.inventrack.inventory.entity; import jakarta.persistence.*; import lombok.*; import java.math.BigDecimal; @Getter @Setter @NoArgsConstructor @Entity @Table(name="inventory_items") public class InventoryItem { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Integer id; @Column(nullable=false,unique=true,length=20) private String sku; @Column(nullable=false) private Integer stockQuantity; @Column(nullable=false,precision=12,scale=2) private BigDecimal unitPrice; }
